import React, { useState, useEffect } from 'react';
import { Card, Form, Button, Badge } from 'react-bootstrap';
import { FileText, Edit2, Download } from 'lucide-react';
import { toast } from 'react-toastify';
import jsPDF from 'jspdf';
import './LetterTemplates.css';

const LetterTemplates = () => {
  const [selectedEmployee, setSelectedEmployee] = useState(null);
  const [employees] = useState([
    { id: 'EMP001', name: 'Rajesh Kumar', store: 'Store 1', role: 'Manager', position: 'Store Manager', joiningDate: '2020-01-15', salary: '₹50,000', reportingManager: 'Regional Manager' },
    { id: 'EMP002', name: 'Priya Singh', store: 'Store 2', role: 'Cashier', position: 'Cashier', joiningDate: '2021-03-20', salary: '₹25,000', reportingManager: 'Store Manager' },
    { id: 'EMP003', name: 'Amit Patel', store: 'Store 3', role: 'Supervisor', position: 'Supervisor', joiningDate: '2019-06-10', salary: '₹35,000', reportingManager: 'Store Manager' },
    { id: 'EMP004', name: 'Sneha Reddy', store: 'Store 4', role: 'Attendant', position: 'Sales Attendant', joiningDate: '2022-01-05', salary: '₹20,000', reportingManager: 'Supervisor' },
    { id: 'EMP005', name: 'Vikram Sharma', store: 'Store 5', role: 'Sales Associate', position: 'Sales Associate', joiningDate: '2021-08-15', salary: '₹22,000', reportingManager: 'Supervisor' }
  ]);

  const [templates] = useState([
    {
      id: 'T001',
      name: 'Warning Letter',
      content: `Date: {{Date}}

To,
{{EmployeeName}}
{{Store}}

Subject: Warning Letter

Dear {{EmployeeName}},

This letter serves as a formal warning regarding your recent conduct/performance. We have noticed certain areas that require immediate attention and improvement.

We expect you to take this warning seriously and make the necessary improvements in your work performance and conduct. Further violations or failure to improve may result in disciplinary action, including possible termination.

We hope this serves as an opportunity for you to reflect and improve. We are confident that with your cooperation, we can resolve these issues.

Please acknowledge receipt of this warning letter.

Regards,
HR Department
Centralized Employee Document Management System`,
      variables: ['Date', 'EmployeeName', 'Store']
    },
    {
      id: 'T002',
      name: 'Offer Letter',
      content: `Date: {{Date}}

Dear {{EmployeeName}},

We are pleased to offer you the position of {{Position}} at {{Store}}.

Your employment will commence on {{JoiningDate}}.

Position Details:
- Position: {{Position}}
- Store Location: {{Store}}
- Salary: {{Salary}}
- Reporting To: {{ReportingManager}}

Please confirm your acceptance of this offer by signing below and returning this letter to us within 7 days.

We look forward to welcoming you to our team.

Sincerely,
HR Department
Centralized Employee Document Management System

_________________________
Employee Signature`,
      variables: ['Date', 'EmployeeName', 'Position', 'Store', 'JoiningDate', 'Salary', 'ReportingManager']
    }
  ]);

  const replaceVariables = (template, employee) => {
    if (!employee) return template.content;

    let content = template.content;
    const today = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

    content = content.replace(/{{Date}}/g, today);
    content = content.replace(/{{EmployeeName}}/g, employee.name);
    content = content.replace(/{{Store}}/g, employee.store);
    content = content.replace(/{{Position}}/g, employee.position || employee.role);
    content = content.replace(/{{JoiningDate}}/g, employee.joiningDate || 'TBD');
    content = content.replace(/{{Salary}}/g, employee.salary || 'As per company policy');
    content = content.replace(/{{ReportingManager}}/g, employee.reportingManager || 'Store Manager');

    return content;
  };

  const handleGeneratePDF = (template) => {
    if (!selectedEmployee) {
      toast.error('Please select an employee first');
      return;
    }

    const content = replaceVariables(template, selectedEmployee);
    
    const pdf = new jsPDF();
    const lines = pdf.splitTextToSize(content, 180);
    
    pdf.setFontSize(12);
    pdf.text(lines, 15, 20);
    
    const fileName = `${template.name}_${selectedEmployee.name.replace(/\s+/g, '_')}.pdf`;
    pdf.save(fileName);
    
    toast.success('Letter generated and downloaded successfully!');
  };

  const handleEditTemplate = (template) => {
    toast.info(`Template editing feature coming soon! Template: ${template.name}`);
  };

  return (
    <div className="letter-templates">
      <Card className="templates-card">
        <Card.Header className="card-header-custom">
          <h3 className="mb-0">
            <FileText className="me-2" size={24} />
            Letter Templates & Printing
          </h3>
        </Card.Header>
        <Card.Body>
          {/* Employee Selection */}
          <Card className="employee-select-card mb-4">
            <Card.Body>
              <Form.Label className="fw-bold mb-3">Select Employee for Auto-fill</Form.Label>
              <Form.Select
                value={selectedEmployee?.id || ''}
                onChange={(e) => {
                  const emp = employees.find(emp => emp.id === e.target.value);
                  setSelectedEmployee(emp || null);
                }}
                size="lg"
              >
                <option value="">Select an employee...</option>
                {employees.map(emp => (
                  <option key={emp.id} value={emp.id}>
                    {emp.name} - {emp.id} ({emp.store})
                  </option>
                ))}
              </Form.Select>
              {selectedEmployee && (
                <div className="mt-3 p-3 bg-light rounded">
                  <strong>Selected:</strong> {selectedEmployee.name} ({selectedEmployee.id}) - {selectedEmployee.store}
                </div>
              )}
            </Card.Body>
          </Card>

          {/* Templates Grid */}
          <div className="row g-4">
            {templates.map(template => {
              const filledContent = replaceVariables(template, selectedEmployee);
              const hasPlaceholders = filledContent.includes('{{');
              
              return (
                <div key={template.id} className="col-md-6">
                  <Card className="template-card h-100">
                    <Card.Body>
                      <div className="d-flex justify-content-between align-items-start mb-3">
                        <div>
                          <h4 className="mb-1">{template.name}</h4>
                          <Badge bg="secondary">ID: {template.id}</Badge>
                        </div>
                        <Button
                          variant="outline-primary"
                          size="sm"
                          onClick={() => handleEditTemplate(template)}
                          className="edit-btn"
                        >
                          <Edit2 size={16} className="me-1" />
                          Edit
                        </Button>
                      </div>

                      {/* Variables */}
                      <div className="mb-3">
                        <small className="text-muted d-block mb-2">Variables:</small>
                        <div className="variables-container">
                          {template.variables.map(variable => (
                            <Badge key={variable} bg="info" className="variable-badge">
                              {variable}
                            </Badge>
                          ))}
                        </div>
                      </div>

                      {/* Preview */}
                      <div className="template-preview mb-3">
                        <small className="text-muted d-block mb-2">Preview:</small>
                        <div className="preview-content">
                          {filledContent.split('\n').slice(0, 8).map((line, idx) => (
                            <div key={idx} className="preview-line">
                              {line || '\u00A0'}
                            </div>
                          ))}
                          {filledContent.split('\n').length > 8 && (
                            <div className="text-muted small">...</div>
                          )}
                        </div>
                      </div>

                      {hasPlaceholders && selectedEmployee && (
                        <div className="alert alert-warning small mb-3">
                          Some placeholders remain unfilled. Please ensure all employee data is complete.
                        </div>
                      )}

                      <Button
                        variant="success"
                        className="w-100 generate-btn"
                        onClick={() => handleGeneratePDF(template)}
                        disabled={!selectedEmployee}
                      >
                        <Download className="me-2" size={18} />
                        Generate & Download PDF
                      </Button>
                    </Card.Body>
                  </Card>
                </div>
              );
            })}
          </div>
        </Card.Body>
      </Card>
    </div>
  );
};

export default LetterTemplates;
